import math
from collections import defaultdict
from sortedcontainers import SortedList

class Solution(object):
    def subarrayMajority(self, nums, queries):
        n = len(nums)
        B = max(1, int(math.isqrt(n)))
        # Sort queries Mo's order
        q_sorted = sorted(enumerate(queries), key=lambda x: (x[1][0] // B,
            x[1][1] if (x[1][0] // B) % 2 == 0 else -x[1][1]))
        cnt = defaultdict(int)
        # freq_inv[f] = SortedList of values with count == f
        freq_inv = defaultdict(SortedList)
        max_freq = [0]
        def add(x):
            f = cnt[x]
            if f > 0:
                freq_inv[f].remove(x)
                if not freq_inv[f]:
                    del freq_inv[f]
            cnt[x] = f + 1
            freq_inv[f+1].add(x)
            if f + 1 > max_freq[0]:
                max_freq[0] = f + 1
        def remove(x):
            f = cnt[x]
            freq_inv[f].remove(x)
            if not freq_inv[f]:
                del freq_inv[f]
                if max_freq[0] == f:
                    max_freq[0] = max(freq_inv) if freq_inv else 0
            cnt[x] = f - 1
            if f - 1 > 0:
                freq_inv[f-1].add(x)
        L, R = 0, -1
        ans = [-1] * len(queries)
        for qi, (l, r, threshold) in q_sorted:
            while R < r: R += 1; add(nums[R])
            while L > l: L -= 1; add(nums[L])
            while R > r: remove(nums[R]); R -= 1
            while L < l: remove(nums[L]); L += 1
            result = -1
            for f in range(max_freq[0], threshold - 1, -1):
                if f in freq_inv and freq_inv[f]:
                    result = freq_inv[f][0]
                    break
            ans[qi] = result
        return ans
